 1→import { useLocation, useNavigate } from 'react-router-dom';
 2→import './sidebar.css'
 3→import React, { useEffect, useState, useRef } from "react";
 4→import { useAuth } from '../../Context/useAuth';
 5→import { useTheme } from '../../Context/useTheme';
 6→import VerifiedBadge from '../Badge/VerifiedBadge';
 7→import StreakBadge from '../Streak/StreakBadge';
