12→    const {theme, toggleTheme} = useTheme();
13→    const navigate = useNavigate(null)
14→    const location = useLocation();
15→
16→    const userData = user?.userData?.[0];
17→    const { data: streakData } = useStreakData(userData?.id);
18→    return(
19→        <>
20→        <div className='side-bar-container'>
21→            <div className='sidebar-header'>
22→                Iskrib
23→            </div>
24→            {links.map((link, index) => {   
25→                return(
26→                <div className={link.className ? link.className : location.pathname === link.path ? 'sidebar-links-active' : 'sidebar-links'} onClick={link.action} key={index}>
27→                    <div className='icon-container'>
28→                        {link.icon}
29→                        {link.notifCount && (
30→                            <div className='notification-count'>{link.notifCount}</div>
31→                        )}
32→                    </div>   
33→
34→                    {link.label}
35→                </div>
36→                )
37→            })}
38→            <div className='sidebar-theme-toggle' onClick={toggleTheme}>
39→                <span>{theme === 'dark' ? 'Light mode' : 'Dark mode'}</span>
40→                <div className={`theme-toggle-track ${theme === 'dark' ? 'active' : ''}`}>
41→                    <div className='theme-toggle-thumb'/>
42→                </div>
43→            </div>
44→            <div className='sidebar-user-container'>
45→                {userData && (
46→                    <>
47→                    <div className='sidebar-avatar-container'>
48→                        <img loading='lazy' className='sidebar-avatar' src={userData.image_url || '/assets/profile.jpg'} alt={`${userData?.name || "User"} profile picture`} />
49→
50→                        <div className='sidebar-metadata-container'>
51→                            <span className='sidebar-name'>{userData.name}<VerifiedBadge badge={userData.badge} size={14} /><StreakBadge count={streakData?.current_streak} size={14} /></span>
52→                            <span className='sidebar-email'>{session?.user.email}</span>
53→                        </div>
54→                    </div>
55→                    <div className='side-bar-logout-container'>
56→                        <div onClick={signOut}>
57→                            Sign Out
58→                        </div>
59→                    </div>
60→                    </>                  
61→                )}
62→            </div>
63→        </div>
64→        </>
65→    )
66→}
67→export default Sidebar;
