  1→import React, { useEffect, useState, useCallback, useMemo } from "react";
  2→import './home.css'
  3→import { useAuth } from "../../Context/useAuth";
  4→import { useNavigate, Outlet, useLocation } from "react-router-dom";
  5→import Sidebar from "../SideBar/Sidebar";
  6→import { AnimatePresence } from "framer-motion";
  7→
  8→import { useQueryClient } from '@tanstack/react-query';
  9→import Editor from "./Editor/Editor";
 10→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
 11→import MobileNavlink from "../mobileNavLink/MobileNavLink";
 12→import WriteJournalButton from "../WriteJournalButton/WriteJournalButton";
 13→import MobileSidebarLink from "../MobileSidebarLink/MobileSidebarLink";
 14→import OnboardingWizard from "../Onboarding/OnboardingWizard";
 15→import Loader from "../loadingComponent/BgLoader";
 16→import SidebarOpinions from "../SidebarOpinions/SidebarOpinions";
 17→import OpinionEditor from "../SidebarOpinions/OpinionsEditor";
 18→
 19→import { useMediaQuery } from 'react-responsive';
 20→
 21→const DEFAULT_EDITOR_LAUNCH_CONFIG = {
 22→    initialTitle: '',
 23→    promptId: null,
 24→    promptText: null
 25→};
 26→
 27→const HomePage = () => {
 28→    const {session, signOut, user, loading, isLoading, notifCount, openAuthModal} = useAuth();
 29→    const isGuest = !session && !loading;
 30→
 31→    const userId = user?.userData?.[0]?.id || null;
 32→
 33→    const isMobile = useMediaQuery({query: '(max-width: 480px)'});
 34→
 35→    const navigate = useNavigate();
 36→    const location = useLocation();
 37→
 38→    const queryClient = useQueryClient();
 39→    const [editor] = useLexicalComposerContext();
 40→
 41→    const [showMobileSideBar, setShowMobileSideBar] = useState(false);
 42→
 43→    const isOpinionsPage = location.pathname === '/home/opinions';
 44→    const isOpinionsViewer = location.pathname === '/home/opinionsViewer';
 45→
 46→    const navigatePath = useCallback((path) => {
 47→        if(window.location.pathname === path){
 48→           return window.location.reload()
 49→        }
 50→        return navigate(path);
 51→    }, [navigate])
 52→
 53→    const [showOnboarding, setShowOnboarding] = useState(false);
 54→    const [onboardingUserExists, setOnboardingUserExists] = useState(false);
 55→    const [showEditor, setShowEditor] = useState(false);
 56→    const [editorLaunchConfig, setEditorLaunchConfig] = useState(DEFAULT_EDITOR_LAUNCH_CONFIG);
 57→
 58→    const [showOpinionEditor, setShowOpinionEditor] = useState(false);
 59→
 60→    const handleOpenTextEditor = useCallback((config = {}) => {
 61→        editor.setEditable(true)
 62→        setEditorLaunchConfig({
 63→            ...DEFAULT_EDITOR_LAUNCH_CONFIG,
