 31→const SettingsPage = () => {
 32→    const { session, user } = useAuth();
 33→    const queryClient = useQueryClient();
 34→    const navigate = useNavigate();
 35→    const [searchParams, setSearchParams] = useSearchParams();
 36→    const isRecovery = searchParams.get('recovery') === 'true';
 37→
 38→    // Password state
 39→    const [currentPassword, setCurrentPassword] = useState('');
 40→    const [newPassword, setNewPassword] = useState('');
 41→    const [confirmPassword, setConfirmPassword] = useState('');
 42→    const [showCurrentPass, setShowCurrentPass] = useState(false);
 43→    const [showNewPass, setShowNewPass] = useState(false);
 44→    const [passwordLoading, setPasswordLoading] = useState(false);
 45→    const [passwordError, setPasswordError] = useState('');
 46→    const [passwordSuccess, setPasswordSuccess] = useState('');
 47→
 48→    // Email state
 49→    const [newEmail, setNewEmail] = useState('');
 50→    const [emailLoading, setEmailLoading] = useState(false);
 51→    const [emailError, setEmailError] = useState('');
 52→    const [emailSuccess, setEmailSuccess] = useState('');
 53→
 54→    // Interests state
 55→    const userData = user?.userData?.[0];
 56→    const [interests, setInterests] = useState([]);
 57→    const [goal, setGoal] = useState('');
 58→    const [interestsLoading, setInterestsLoading] = useState(false);
 59→    const [interestsError, setInterestsError] = useState('');
 60→    const [interestsSuccess, setInterestsSuccess] = useState('');
 61→
 62→    useEffect(() => {
 63→        if(userData){
 64→            setInterests(Array.isArray(userData.writing_interests) ? userData.writing_interests : []);
 65→            setGoal(userData.writing_goal || '');
 66→        }
 67→    }, [userData]);
 68→
 69→    const toggleTopic = (topic) => {
 70→        setInterests((prev) =>
 71→            prev.includes(topic)
 72→                ? prev.filter((t) => t !== topic)
 73→                : [...prev, topic]
 74→        );
 75→        setInterestsSuccess('');
 76→    };
 77→
 78→    const handleSaveInterests = async (e) => {
 79→        e.preventDefault();
 80→        setInterestsError('');
 81→        setInterestsSuccess('');
 82→        setInterestsLoading(true);
 83→
 84→        try {
 85→            await updateInterests(session?.access_token, {
 86→                writingInterests: interests,
 87→                writingGoal: goal || undefined,
 88→            });
 89→            setInterestsSuccess('Writing preferences updated.');
 90→            queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
 91→            queryClient.removeQueries({ queryKey: ['journals-for-you'] });
 92→        } catch (err) {
 93→            setInterestsError(err?.message || 'Something went wrong. Please try again.');
 94→        } finally {
 95→            setInterestsLoading(false);
 96→        }
 97→    };
 98→
 99→    const handleChangePassword = async (e) => {
100→        e.preventDefault();
101→        setPasswordError('');
102→        setPasswordSuccess('');
103→
104→        if (newPassword.length < 6) {
105→            return setPasswordError('New password must be at least 6 characters.');
106→        }
107→        if (newPassword !== confirmPassword) {
108→            return setPasswordError('Passwords do not match.');
109→        }
110→
111→        setPasswordLoading(true);
112→        try {
113→            if (!isRecovery) {
114→                // Verify current password
115→                const { error: signInError } = await supabase.auth.signInWithPassword({
116→                    email: session.user.email,
117→                    password: currentPassword,
118→                });
119→                if (signInError) {
120→                    setPasswordLoading(false);
121→                    return setPasswordError('Current password is incorrect.');
122→                }
123→            }
124→
125→            // Update to new password
126→            const { error: updateError } = await supabase.auth.updateUser({
127→                password: newPassword,
128→            });
129→            if (updateError) {
130→                setPasswordLoading(false);
131→                return setPasswordError(updateError.message);
132→            }
133→
134→            setPasswordSuccess('Password updated successfully.');
135→            setCurrentPassword('');
136→            setNewPassword('');
137→            setConfirmPassword('');
138→
139→            // Clear recovery param from URL
140→            if (isRecovery) {
141→                searchParams.delete('recovery');
142→                setSearchParams(searchParams, { replace: true });
143→            }
144→        } catch (err) {
145→            setPasswordError('Something went wrong. Please try again.');
146→        } finally {
147→            setPasswordLoading(false);
148→        }
149→    };
150→
151→    const handleChangeEmail = async (e) => {
152→        e.preventDefault();
153→        setEmailError('');
154→        setEmailSuccess('');
155→
156→        if (!newEmail || !newEmail.includes('@')) {
157→            return setEmailError('Please enter a valid email address.');
158→        }
159→        if (newEmail === session.user.email) {
160→            return setEmailError('This is already your current email.');
161→        }
162→
163→        setEmailLoading(true);
164→        try {
165→            const { error } = await supabase.auth.updateUser({
166→                email: newEmail,
167→            });
168→            if (error) {
169→                setEmailLoading(false);
170→                return setEmailError(error.message);
171→            }
172→
173→            setEmailSuccess('Confirmation email sent to ' + newEmail + '. Please check your inbox.');
174→            setNewEmail('');
175→        } catch (err) {
176→            setEmailError('Something went wrong. Please try again.');
177→        } finally {
178→            setEmailLoading(false);
179→        }
180→    };
181→
182→    if (!session) {
183→        return null;
184→    }
185→
186→    const isPasswordDisabled = (!isRecovery && !currentPassword) || !newPassword || !confirmPassword || passwordLoading;
187→    const isEmailDisabled = !newEmail || emailLoading;
188→
189→    return (
190→        <div className="settings-page">
191→            <div className="settings-header">
192→                <button className="settings-back-btn" onClick={() => navigate(-1)} aria-label="Go back">
193→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
194→                        <path d="M19 12H5"/>
195→                        <path d="M12 19l-7-7 7-7"/>
196→                    </svg>
197→                </button>
198→                <h1 className="settings-title">Settings</h1>
199→            </div>
200→
201→            {/* Change Password Section */}
202→            <section className="settings-section">
203→                <h2 className="settings-section-title">
204→                    {isRecovery ? 'Set New Password' : 'Change Password'}
205→                </h2>
206→                <form className="settings-form" onSubmit={handleChangePassword}>
207→                    {!isRecovery && (
208→                        <div className="settings-field">
209→                            <label htmlFor="current-password">Current Password</label>
210→                            <div className="input-with-action">
211→                                <input
212→                                    id="current-password"
213→                                    type={showCurrentPass ? 'text' : 'password'}
214→                                    value={currentPassword}
215→                                    onChange={(e) => setCurrentPassword(e.target.value)}
216→                                    placeholder="Enter current password"
217→                                    className="auth-input"
218→                                    autoComplete="current-password"
219→                                />
220→                                <button
221→                                    className="show-toggle"
222→                                    type="button"
223→                                    onClick={() => setShowCurrentPass((p) => !p)}
224→                                >
225→                                    {showCurrentPass ? 'Hide' : 'Show'}
226→                                </button>
227→                            </div>
228→                        </div>
229→                    )}
230→
231→                    <div className="settings-field">
232→                        <label htmlFor="new-password">New Password</label>
233→                        <div className="input-with-action">
234→                            <input
235→                                id="new-password"
236→                                type={showNewPass ? 'text' : 'password'}
237→                                value={newPassword}
238→                                onChange={(e) => setNewPassword(e.target.value)}
239→                                placeholder="At least 6 characters"
240→                                className="auth-input"
241→                                autoComplete="new-password"
242→                            />
243→                            <button
244→                                className="show-toggle"
245→                                type="button"
246→                                onClick={() => setShowNewPass((p) => !p)}
247→                            >
248→                                {showNewPass ? 'Hide' : 'Show'}
249→                            </button>
250→                        </div>
251→                    </div>
252→
253→                    <div className="settings-field">
254→                        <label htmlFor="confirm-password">Confirm New Password</label>
255→                        <input
256→                            id="confirm-password"
257→                            type="password"
258→                            value={confirmPassword}
259→                            onChange={(e) => setConfirmPassword(e.target.value)}
260→                            placeholder="Re-enter new password"
261→                            className="auth-input"
262→                            autoComplete="new-password"
263→                        />
264→                    </div>
265→
266→                    <button className="primary-button" type="submit" disabled={isPasswordDisabled}>
267→                        <span className="button-label">{isRecovery ? 'Set New Password' : 'Update Password'}</span>
268→                        {passwordLoading && <span className="button-spinner" aria-hidden="true" />}
269→                    </button>
270→                </form>
271→
272→                {passwordError && (
273→                    <div className="form-message error" role="alert">{passwordError}</div>
274→                )}
275→                {passwordSuccess && (
276→                    <div className="form-message success" role="status">{passwordSuccess}</div>
277→                )}
278→            </section>
279→
280→            {/* Change Email Section */}
281→            <section className="settings-section">
282→                <h2 className="settings-section-title">Change Email</h2>
283→                <p className="settings-current-value">
284→                    Current email: <strong>{session.user.email}</strong>
285→                </p>
286→                <form className="settings-form" onSubmit={handleChangeEmail}>
287→                    <div className="settings-field">
288→                        <label htmlFor="new-email">New Email</label>
289→                        <input
290→                            id="new-email"
291→                            type="email"
292→                            value={newEmail}
293→                            onChange={(e) => setNewEmail(e.target.value)}
294→                            placeholder="you@example.com"
295→                            className="auth-input"
296→                            autoComplete="email"
297→                        />
298→                    </div>
299→
300→                    <button className="primary-button" type="submit" disabled={isEmailDisabled}>
301→                        <span className="button-label">Send Confirmation Email</span>
302→                        {emailLoading && <span className="button-spinner" aria-hidden="true" />}
303→                    </button>
304→                </form>
305→
306→                {emailError && (
307→                    <div className="form-message error" role="alert">{emailError}</div>
308→                )}
309→                {emailSuccess && (
310→                    <div className="form-message success" role="status">{emailSuccess}</div>
311→                )}
312→            </section>
313→
314→            {/* Writing Preferences Section */}
315→            <section className="settings-section">
316→                <h2 className="settings-section-title">Writing Preferences</h2>
317→                <p className="settings-current-value">
318→                    Choose topics you enjoy and your main writing goal. This personalizes your For You feed and Explore sections.
319→                </p>
320→
321→                <div className="settings-field">
322→                    <label>Topics</label>
323→                    <div className="settings-interests-grid">
324→                        {TOPICS.map((topic) => (
325→                            <button
326→                                key={topic}
327→                                type="button"
328→                                className={`settings-interest-chip ${interests.includes(topic) ? 'selected' : ''}`}
329→                                onClick={() => toggleTopic(topic)}
330→                            >
331→                                {topic}
332→                            </button>
333→                        ))}
334→                    </div>
335→                </div>
336→
337→                <div className="settings-field">
338→                    <label>Writing Goal</label>
339→                    <div className="settings-goal-grid">
340→                        {GOALS.map((g) => (
341→                            <button
342→                                key={g.id}
343→                                type="button"
344→                                className={`settings-goal-card ${goal === g.id ? 'selected' : ''}`}
345→                                onClick={() => { setGoal(g.id); setInterestsSuccess(''); }}
346→                            >
347→                                <span className="settings-goal-icon">{g.icon}</span>
348→                                <span className="settings-goal-label">{g.label}</span>
349→                            </button>
350→                        ))}
351→                    </div>
352→                </div>
353→
354→                <button
355→                    className="primary-button"
356→                    onClick={handleSaveInterests}
357→                    disabled={interestsLoading}
358→                >
359→                    <span className="button-label">Save Preferences</span>
